// client/hooks/useEventListener.ts
import { useEffect, useRef, RefObject } from 'react';
type Target = Window | Document | HTMLElement | null;
export function useEventListener<K extends keyof WindowEventMap>(eventName: K, handler: (e: WindowEventMap[K]) => void, element?: Window, options?: AddEventListenerOptions): void;
export function useEventListener<K extends keyof DocumentEventMap>(eventName: K, handler: (e: DocumentEventMap[K]) => void, element: Document, options?: AddEventListenerOptions): void;
export function useEventListener<K extends keyof HTMLElementEventMap>(eventName: K, handler: (e: HTMLElementEventMap[K]) => void, element: RefObject<HTMLElement>, options?: AddEventListenerOptions): void;
export function useEventListener(eventName: string, handler: (e: Event) => void, element?: any, options?: AddEventListenerOptions) {
  const handlerRef = useRef(handler);
  useEffect(() => { handlerRef.current = handler; }, [handler]);
  useEffect(() => {
    const target: Target = element && 'current' in element ? element.current : (element ?? (typeof window !== 'undefined' ? window : null));
    if (!target?.addEventListener) return;
    const listener = (e: Event) => handlerRef.current(e);
    target.addEventListener(eventName, listener, options);
    return () => target.removeEventListener(eventName, listener, options);
  }, [eventName, element, options]);
}

// client/hooks/useClickOutside.ts
import { useEffect, useRef, RefObject } from 'react';
type Ref = RefObject<HTMLElement>;
export function useClickOutside(refs: Ref | Ref[], handler: (e: MouseEvent | TouchEvent) => void, opts: { enabled?: boolean; ignoreSelectors?: string[] } = {}) {
  const handlerRef = useRef(handler);
  useEffect(() => { handlerRef.current = handler; }, [handler]);
  useEffect(() => {
    if (opts.enabled === false) return;
    const refArray = Array.isArray(refs) ? refs : [refs];
    const onPointerDown = (e: MouseEvent | TouchEvent) => {
      const path = (e.composedPath?.() ?? [e.target]) as Element[];
      for (const r of refArray) if (r.current && path.includes(r.current)) return;
      for (const sel of opts.ignoreSelectors ?? []) if (path.some(el => el?.matches?.(sel))) return;
      handlerRef.current(e);
    };
    document.addEventListener('mousedown', onPointerDown);
    document.addEventListener('touchstart', onPointerDown, { passive: true });
    return () => {
      document.removeEventListener('mousedown', onPointerDown);
      document.removeEventListener('touchstart', onPointerDown);
    };
  }, [refs, opts.enabled, opts.ignoreSelectors?.join(',')]);
}

// client/hooks/useMediaQuery.ts
import { useSyncExternalStore } from 'react';
export function useMediaQuery(query: string, ssrFallback = false): boolean {
  const subscribe = (cb: () => void) => {
    if (typeof window === 'undefined' || !window.matchMedia) return () => {};
    const mql = window.matchMedia(query);
    mql.addEventListener('change', cb);
    return () => mql.removeEventListener('change', cb);
  };
  const getSnapshot = () => typeof window !== 'undefined' && window.matchMedia ? window.matchMedia(query).matches : ssrFallback;
  const getServerSnapshot = () => ssrFallback;
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

