// client/hooks/useIdleTimeout.ts
import { useEffect, useRef, useState } from 'react';
export function useIdleTimeout({ idleMs, graceMs, onIdle, onWarn }: { idleMs: number; graceMs: number; onIdle: () => void; onWarn: () => void }) {
  const lastActivityRef = useRef(Date.now());
  const [state, setState] = useState<'active' | 'warning' | 'idle'>('active');
  useEffect(() => {
    const channel = typeof BroadcastChannel !== 'undefined' ? new BroadcastChannel('idle-activity') : null;
    const onActivity = () => {
      lastActivityRef.current = Date.now();
      setState('active');
      channel?.postMessage('activity');
    };
    ['mousedown','keydown','touchstart','scroll'].forEach(e => window.addEventListener(e, onActivity, { passive: true }));
    if (channel) channel.onmessage = () => { lastActivityRef.current = Date.now(); setState('active'); };
    const interval = setInterval(() => {
      const elapsed = Date.now() - lastActivityRef.current;
      if (elapsed >= idleMs + graceMs) { setState('idle'); onIdle(); }
      else if (elapsed >= idleMs) { if (state !== 'warning') { setState('warning'); onWarn(); } }
    }, 1000);
    return () => {
      ['mousedown','keydown','touchstart','scroll'].forEach(e => window.removeEventListener(e, onActivity));
      clearInterval(interval);
      channel?.close();
    };
  }, [idleMs, graceMs, onIdle, onWarn]);
  return state;
}

// client/hooks/useAsync.ts
import { useCallback, useRef, useState } from 'react';
type State<T,E=Error> = { status: 'idle' } | { status: 'pending' } | { status: 'success'; data: T } | { status: 'error'; error: E };
export function useAsync<T, Args extends any[], E = Error>(fn: (signal: AbortSignal, ...args: Args) => Promise<T>) {
  const [state, setState] = useState<State<T,E>>({ status: 'idle' });
  const counter = useRef(0);
  const controllerRef = useRef<AbortController | null>(null);
  const execute = useCallback(async (...args: Args) => {
    const id = ++counter.current;
    controllerRef.current?.abort();
    const controller = new AbortController();
    controllerRef.current = controller;
    setState({ status: 'pending' });
    try {
      const data = await fn(controller.signal, ...args);
      if (counter.current === id) setState({ status: 'success', data });
      return data;
    } catch (error) {
      if (controller.signal.aborted) return;
      if (counter.current === id) setState({ status: 'error', error: error as E });
      throw error;
    }
  }, [fn]);
  const reset = useCallback(() => { controllerRef.current?.abort(); counter.current++; setState({ status: 'idle' }); }, []);
  return { state, execute, reset };
}

