// server/router/createRouter.ts — auto-wraps async handlers
import { Router, RequestHandler } from 'express';
import { asyncHandler } from '../lib/asyncHandler';
export function createRouter() {
  const r = Router();
  const wrap = (handlers: RequestHandler[]) => handlers.map(h => h.constructor.name === 'AsyncFunction' ? asyncHandler(h as any) : h);
  return {
    get: (path: string, ...handlers: RequestHandler[]) => r.get(path, ...wrap(handlers)),
    post: (path: string, ...handlers: RequestHandler[]) => r.post(path, ...wrap(handlers)),
    put: (path: string, ...handlers: RequestHandler[]) => r.put(path, ...wrap(handlers)),
    patch: (path: string, ...handlers: RequestHandler[]) => r.patch(path, ...wrap(handlers)),
    delete: (path: string, ...handlers: RequestHandler[]) => r.delete(path, ...wrap(handlers)),
    use: (...args: any[]) => r.use(...args),
    raw: r
  };
}

