// server/lib/sentry.ts
import * as Sentry from '@sentry/node';
import { SENSITIVE_KEYS } from '@shared/constants/pii';
function redact(obj: any, depth = 0): any {
  if (depth > 5 || obj == null) return obj;
  if (typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(o => redact(o, depth + 1));
  const out: any = {};
  for (const [k, v] of Object.entries(obj)) {
    out[k] = SENSITIVE_KEYS.includes(k.toLowerCase()) ? '[REDACTED]' : redact(v, depth + 1);
  }
  return out;
}
export function initSentry() {
  Sentry.init({
    dsn: process.env.SENTRY_DSN,
    environment: process.env.NODE_ENV,
    tracesSampleRate: 0.1,
    beforeSend(event) {
      if (event.request) {
        if (event.request.data) event.request.data = redact(event.request.data);
        if (event.request.headers) event.request.headers = redact(event.request.headers);
        if (event.request.cookies) event.request.cookies = '[REDACTED]';
      }
      if (event.extra) event.extra = redact(event.extra);
      return event;
    },
    beforeBreadcrumb(breadcrumb) {
      if (breadcrumb.data) breadcrumb.data = redact(breadcrumb.data);
      return breadcrumb;
    }
  });
}

