// client/lib/errorPresentation.ts
import type { FetchError } from './fetcher';
import { toast } from './toast';
import { showBanner, showModal } from './globalUi';
export function presentError(err: FetchError | Error, override?: { presentation?: 'toast'|'banner'|'modal'; action?: { label: string; onClick: () => void } }) {
  if (!(err instanceof FetchError)) {
    toast.error('Something went wrong', { action: override?.action });
    return;
  }
  const code = err.body?.code;
  const presentation = override?.presentation ?? (err.body?.meta?.presentation as any) ?? defaultPresentation(code);
  const message = err.body?.message ?? 'An error occurred';
  switch (presentation) {
    case 'toast': toast.error(message, { action: override?.action }); break;
    case 'banner': showBanner({ severity: 'warning', message, action: override?.action }); break;
    case 'modal': showModal({ title: titleFor(code), message, primaryAction: override?.action ?? defaultActionFor(code), dismissible: false }); break;
  }
}
function defaultPresentation(code?: string): 'toast'|'banner'|'modal' {
  if (!code) return 'toast';
  if (['UNAUTHORIZED','BILLING_PAST_DUE','SESSION_EXPIRED'].includes(code)) return 'modal';
  if (['QUOTA_EXCEEDED','FORBIDDEN','VALIDATION_FAILED'].includes(code)) return 'banner';
  return 'toast';
}
function titleFor(code?: string) {
  if (code === 'BILLING_PAST_DUE') return 'Subscription past due';
  if (code === 'UNAUTHORIZED') return 'Sign in required';
  return 'Action required';
}
function defaultActionFor(code?: string) {
  if (code === 'BILLING_PAST_DUE') return { label: 'Update payment', onClick: () => window.location.assign('/billing') };
  if (code === 'UNAUTHORIZED') return { label: 'Sign in', onClick: () => window.location.assign('/login') };
  return { label: 'Retry', onClick: () => window.location.reload() };
}

