// server/lib/tokenBucket.ts
import { redis } from '../redis';
const LUA = `
local key = KEYS[1]
local capacity = tonumber(ARGV[1])
local refillPerSec = tonumber(ARGV[2])
local now = tonumber(ARGV[3])
local data = redis.call('HMGET', key, 'tokens', 'updatedAt')
local tokens = tonumber(data[1]) or capacity
local updatedAt = tonumber(data[2]) or now
local elapsed = math.max(0, now - updatedAt)
local newTokens = math.min(capacity, tokens + elapsed * refillPerSec)
local allowed = 0
if newTokens >= 1 then
  newTokens = newTokens - 1
  allowed = 1
end
redis.call('HMSET', key, 'tokens', newTokens, 'updatedAt', now)
redis.call('EXPIRE', key, 3600)
local waitSec = 0
if allowed == 0 then waitSec = math.ceil((1 - newTokens) / refillPerSec) end
return {allowed, newTokens, waitSec}
`;
export async function takeToken(key: string, capacity: number, refillPerSec: number) {
  const now = Date.now() / 1000;
  const [allowed, remaining, waitSec] = await redis.eval(LUA, 1, key, capacity, refillPerSec, now) as [number, number, number];
  return { allowed: allowed === 1, remaining, waitSec };
}

// server/middleware/rateLimit.ts
import { RequestHandler } from 'express';
import { takeToken } from '../lib/tokenBucket';
import { RateLimitError } from '../errors';
const PLAN_LIMITS: Record<string, { capacity: number; perSec: number }> = {
  free: { capacity: 60, perSec: 1 },
  pro: { capacity: 600, perSec: 10 },
  enterprise: { capacity: 6000, perSec: 100 }
};
export const rateLimit = (endpointClass: string): RequestHandler => async (req, res, next) => {
  const tenant = (req as any).user?.tenantId;
  const plan = (req as any).user?.plan ?? 'free';
  if (!tenant) return next();
  const limits = PLAN_LIMITS[plan];
  const { allowed, remaining, waitSec } = await takeToken(`rl:${tenant}:${endpointClass}`, limits.capacity, limits.perSec);
  res.set('X-RateLimit-Limit', String(limits.capacity));
  res.set('X-RateLimit-Remaining', String(Math.floor(remaining)));
  res.set('X-RateLimit-Reset', String(Math.floor(Date.now()/1000 + waitSec)));
  if (!allowed) {
    res.set('Retry-After', String(waitSec));
    return next(new RateLimitError('Rate limit exceeded', { meta: { retryAfter: waitSec, plan } }));
  }
  next();
};

