// server/services/inviteService.ts
import { createHmac, randomBytes } from 'crypto';
import { ConflictError, ForbiddenError, NotFoundError } from '../errors';
const SECRET = process.env.INVITE_SECRET!;
const TTL_MS = 7 * 86400 * 1000;
function sign(data: string) { return createHmac('sha256', SECRET).update(data).digest('hex'); }
export const inviteService = {
  async invite(tenantId: string, input: { email: string; role: string }) {
    const [used, pending, limit] = await Promise.all([userDal.countByTenant(tenantId), inviteDal.pendingByTenant(tenantId), planDal.seatLimit(tenantId)]);
    if (used + pending.length >= limit) throw new QuotaError('Seat limit reached', { meta: { used, pending: pending.length, limit, upgradeUrl: '/billing/upgrade' } });
    const existing = await userDal.byEmail(input.email);
    if (existing && existing.tenantId === tenantId) throw new ConflictError('User already a member');
    const id = randomBytes(16).toString('hex');
    const token = `${id}.${sign(id)}`;
    await inviteDal.create({ id, tenantId, email: input.email, role: input.role, expiresAt: new Date(Date.now() + TTL_MS) });
    await emailJob.send({ kind: 'invite', to: input.email, token, tenantName: (await tenantDal.byId(tenantId)).name });
    return { id, expiresAt: new Date(Date.now() + TTL_MS) };
  },
  async accept(input: { token: string; password: string }) {
    const [id, sig] = input.token.split('.');
    if (!id || sign(id) !== sig) throw new NotFoundError('Invalid invite');
    const invite = await inviteDal.byId(id);
    if (!invite || invite.status !== 'pending') throw new NotFoundError('Invalid invite');
    if (invite.expiresAt < new Date()) { await inviteDal.markExpired(id); throw new NotFoundError('Invite expired'); }
    const [used, limit] = await Promise.all([userDal.countByTenant(invite.tenantId), planDal.seatLimit(invite.tenantId)]);
    if (used >= limit) throw new QuotaError('Seat limit reached since invite was sent');
    const user = await userDal.create({ email: invite.email, tenantId: invite.tenantId, role: invite.role, passwordHash: await hashPassword(input.password) });
    await inviteDal.markAccepted(id, user.id);
    return user;
  }
};

