import { useEffect, useRef } from 'react';
import * as echarts from 'echarts';
export function useChartWithLiveData(divRef: React.RefObject<HTMLDivElement>, options: any, streamUrl: string) {
  const chartRef = useRef<echarts.ECharts | null>(null);
  const hoveringRef = useRef(false);
  const queuedRef = useRef<any[]>([]);
  useEffect(() => {
    if (!divRef.current) return;
    chartRef.current = echarts.init(divRef.current);
    chartRef.current.setOption(options);
    const el = divRef.current;
    el.addEventListener('mouseenter', () => { hoveringRef.current = true; });
    el.addEventListener('mouseleave', () => { hoveringRef.current = false; applyQueued(); });
    const applyQueued = () => {
      if (!queuedRef.current.length) return;
      const merged = queuedRef.current.reduce((acc, q) => ({ ...acc, ...q }), {});
      queuedRef.current = [];
      const currentZoom = (chartRef.current?.getOption() as any)?.dataZoom;
      chartRef.current?.setOption({ ...merged, dataZoom: currentZoom }, { notMerge: false });
    };
    const es = new EventSource(streamUrl);
    es.onmessage = (e) => {
      const update = JSON.parse(e.data);
      if (hoveringRef.current) { queuedRef.current.push(update); }
      else {
        const currentZoom = (chartRef.current?.getOption() as any)?.dataZoom;
        chartRef.current?.setOption({ ...update, dataZoom: currentZoom }, { notMerge: false });
      }
    };
    return () => { es.close(); chartRef.current?.dispose(); };
  }, []);
  return chartRef;
}

