    return (tenantCache.get(key) ?? DEFAULTS[key]) as T;
  },
  async set(key: string, value: any) {
    const tenantId = tenantContext.requireTenant();
    await TenantConfigModel.findOneAndUpdate({ tenantId, key }, { value }, { upsert: true });
    cache.get(tenantId)?.set(key, value);
  },
  invalidate(tenantId: string) { cache.delete(tenantId); }
};

