import type Stripe from 'stripe';
import { DunningModel } from '../models/Dunning';
import { emailJob } from '../jobs/emailJob';
export async function handleInvoicePaymentFailed(invoice: Stripe.Invoice) {
  const sub = await subDal.byStripeId(invoice.subscription as string);
  if (!sub) return;
  const existing = await DunningModel.find({ subscriptionId: sub.id, invoiceId: invoice.id });
  const attemptNumber = existing.length + 1;
  if (attemptNumber > 3) return;
  const template = attemptNumber === 1 ? 'gentle' : attemptNumber === 2 ? 'reminder' : 'final';
  await emailJob.send({
    to: sub.contactEmail,
    template: `dunning_${template}`,
    data: {
      tenantName: sub.tenantName,
      amount: invoice.amount_due / 100,
      currency: invoice.currency,
      updatePaymentUrl: `${process.env.APP_URL}/billing/payment-method`,
      nextAttemptAt: invoice.next_payment_attempt ? new Date(invoice.next_payment_attempt * 1000) : null
    }
  });
  await DunningModel.create({ subscriptionId: sub.id, invoiceId: invoice.id, attemptNumber, template, sentAt: new Date() });
}

export async function handleInvoicePaymentSucceeded(invoice: Stripe.Invoice) {
  const sub = await subDal.byStripeId(invoice.subscription as string);
  if (!sub) return;
  const dunning = await DunningModel.find({ subscriptionId: sub.id });
  if (dunning.length > 0) {
    await emailJob.send({ to: sub.contactEmail, template: 'dunning_recovered', data: { tenantName: sub.tenantName } });
    await DunningModel.deleteMany({ subscriptionId: sub.id });
  }
}

