import { useStripe, useElements, CardElement } from '@stripe/react-stripe-js';
import { useState } from 'react';
export function PaymentMethodForm({ onUpdated }: { onUpdated: () => void }) {
  const stripe = useStripe();
  const elements = useElements();
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const submit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setSubmitting(true); setError(null);
    const { setupIntent } = await fetch('/api/billing/setup-intent', { method: 'POST' }).then(r => r.json());
    const result = await stripe.confirmCardSetup(setupIntent.client_secret, { payment_method: { card: elements.getElement(CardElement)! } });
    if (result.error) { setError(result.error.message ?? 'Card error'); setSubmitting(false); return; }
    await fetch('/api/billing/payment-method', { method: 'PUT', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ paymentMethodId: result.setupIntent!.payment_method }) });
    onUpdated();
  };
  return <form onSubmit={submit}><CardElement /><button disabled={submitting} type="submit">Update</button>{error && <p role="alert">{error}</p>}</form>;
}

