// server/services/flagService.ts
import { createHash } from 'crypto';
import { FeatureFlagModel } from '../models/FeatureFlag';
import { tenantContext } from '../context/tenantContext';
const rulesCache = new Map<string, any>();
export const flagService = {
  async isEnabled(name: string): Promise<boolean> {
    const tenantId = tenantContext.requireTenant();
    let rule = rulesCache.get(name);
    if (!rule) { rule = await FeatureFlagModel.findOne({ name }).lean(); if (rule) rulesCache.set(name, rule); }
    if (!rule || rule.killed) return false;
    if (rule.denyList.includes(tenantId)) return false;
    if (rule.allowList.includes(tenantId)) return true;
    const hash = parseInt(createHash('sha256').update(`${name}:${tenantId}`).digest('hex').slice(0, 8), 16);
    return (hash % 100) < rule.rolloutPercent;
  },
  invalidate() { rulesCache.clear(); }
};

