// server fills missing dates with null explicitly
export function fillGaps(points: { t: Date; value: number }[], from: Date, to: Date, step: number) {
  const map = new Map(points.map(p => [p.t.toISOString(), p.value]));
  const out: { t: Date; value: number | null }[] = [];
  for (let t = from.getTime(); t <= to.getTime(); t += step) {
    const iso = new Date(t).toISOString();
    out.push({ t: new Date(t), value: map.get(iso) ?? null });
  }
  return out;
}

