// client/components/SensorChart.tsx
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, ReferenceArea } from 'recharts';
export function SensorChart({ points }: { points: { t: Date; value: number | null }[] }) {
  const gaps = findGapRanges(points);
  return (
    <div className="h-64">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={points}>
          <XAxis dataKey="t" />
          <YAxis />
          <Tooltip formatter={(v: any) => v === null ? 'No data' : v} />
          {gaps.map((g, i) => <ReferenceArea key={i} x1={g.start.toISOString()} x2={g.end.toISOString()} fill="#fbbf24" fillOpacity={0.1} label={{ value: 'No data', position: 'insideTop', fontSize: 10 }} />)}
          <Line dataKey="value" stroke="var(--chart-line)" connectNulls={false} dot={false} />
        </LineChart>
      </ResponsiveContainer>
      {gaps.length > 0 && <p className="text-xs text-gray-500 mt-1">{gaps.length} gap{gaps.length > 1 ? 's' : ''} in data</p>}
    </div>
  );
}
function findGapRanges(points: { t: Date; value: number | null }[]) {
  const gaps: { start: Date; end: Date }[] = [];
  let curr: { start: Date } | null = null;
  for (const p of points) {
    if (p.value === null && !curr) curr = { start: p.t };
    else if (p.value !== null && curr) { gaps.push({ start: curr.start, end: p.t }); curr = null; }
  }
  return gaps;
}

